ptions":[],"answers":[],"score":1,"difficulty":"EASY","sourcePage":58,"confidence":0.52,"needsReview":true},{"id":"draft_549","type":"SHORT_ANSWER","title":"ДААЛГАВАРЫН САН - IV АНГИ 1 7 19 2 19 9 - Асуулт 8","prompt":"залгаврыг зөв залган бичээрэй. Сургууль+ийн=....................... Тэнгэр+ээс= Мөрөөдөл+ийн=","options":[],"answers":[],"score":1,"difficulty":"EASY","sourcePage":58,"confidence":0.52,"needsReview":true},{"id":"draft_550","type":"MCQ","title":"ДААЛГАВАРЫН САН - IV АНГИ 1 7 19 2 19 9 - Асуулт 9","prompt":"Үгийг зөв сонгон бичээрэй. \\ Араг, Арга \\ ........................ухаанаар ажил бүтдэг ..........................савраар аргал түүдэг ДААЛГАВАРЫН САН - IV АНГИ Хувилбар 16 59 ЦООРХОИ ХУВИН Эрт урьд цагт Энэтхэгийн нэгэн ус түгээгч хоёр хувинтай дамнуургаар ус зөөдөг байжээ. Харин хоёр хувингийн нэг нь цоорхой бөгөөд усных нь тал асгарчихаад хүрдэг байв. Энэ байдлаасаа цоорхой хувин ихэд ичиж, харин бүтэн хувин нь өөрөөрөө бахархдаг байв. Иймэрхүү байдлаараа бүтэн хоёр жил үргэлжилж, эцэст нь цоорхой хувин тэсч чадалгүй: -Эзэнтэн минь би өөрөөсөө ихэд ичиж байна. Мөн танаасаа уучлалт гуйхыг хүсч байна гэжээ. -Яагаад? гэж усчин асуухад: -Яагаад? гэвэл би авч ирэх ёстой усныхаа дөнгөж талыг нь авчирдаг. Тэгээд та миний ийм байдлаас болж авах ёстой мөнгөө бүгдийг нь авч чаддаггүй шүү дээ гэхэд усчин хариуд нь: -Чи буцах замдаа замын хажуу талын цэцгүүдийг хараарай гэв. Цоорхой хувин буцахдаа замаа хартал үнэхээр сайхан цэцгүүд ургасан байлаа. Гэсэн хэдий ч хүрэх газраа ирэхэд бас л тал устай байсан тул усчнаас уучлал гуйв. Тэгэхэд усчин цоорхой хувингаасаа: “Замын хажууд зөвхөн чиний талд л цэцгүүд ургасан, харин нөгөө хувингийн талд цэцэг ургаагүй байгааг ажиглав уу” гэж асуугаад: -Үүний учир нь чамайг цоорхой болохоор замын хажуугаар цэцгийн үр суулгасан юм. Ус аваад буцах замдаа чи тэднийг усалж сайхан цэцгүүд ургуулсан. Хоёр жилийн турш би энэхүү цэцгүүдийг түүж эзнийхээ гэрт тавьдаг байсан. Хэрвээ энэ сайхан цэцгүүд байгаагүй бол түүний гэрт аз жаргал авч ирэхгүй байсан шүү дээ хэмээн өгүүлжээ. Үгийн тайлбар : Хувин - ус авдаг сав Өгүүлжээ - ярьсан , бичсэн","options":["БИЧИХ ЧАДВАРЫН ДААЛГАВАР “Баяр баясгалан” сэдвээр 80-100 үгэнд багтаан эх зохиож бичээрэй."],"answers":[],"score":1,"difficulty":"EASY","sourcePage":58,"confidence":0.66,"needsReview":true},{"id":"draft_551","type":"MCQ","title":"ДААЛГАВАРЫН САН - IV АНГИ 1 7 19 2 19 9 - Асуулт 1","prompt":"Ус түгээгч ямар улсын иргэн байсан бэ?","options":["Монгол","Хятад","Өвөр монгол","Энэтхэг"],"answers":[],"score":1,"difficulty":"EASY","sourcePage":59,"confidence":0.66,"needsReview":true},{"id":"draft_552","type":"MCQ","title":"ДААЛГАВАРЫН САН - IV АНГИ 1 7 19 2 19 9 - Асуулт 2","prompt":"Цоорхой хувинтай талд сайхан цэцгүүд ургасан нь юутай холбоотой вэ?","options":["Усчин цэцгийн үр суулгасан","Ус үргэлж гоождог байсан В.Салхин дээд тал байсан","Замын хоёр талд адилхан ургасан"],"answers":[],"score":1,"difficulty":"EASY","sourcePage":59,"confidence":0.66,"needsReview":true},{"id":"draft_553","type":"MCQ","title":"ДААЛГАВАРЫН САН - IV АНГИ 1 7 19 2 19 9 - Асуулт 3","prompt":"Усчин хэдэн хувингаар ус зөөдөг вэ?","options":["2","1 В.Хувингаар биш","3"],"answers":[],"score":1,"difficulty":"EASY","sourcePage":59,"confidence":0.66,"needsReview":true},{"id":"draft_554","type":"SHORT_ANSWER","title":"ДААЛГАВАРЫН САН - IV АНГИ 1 7 19 2 19 9 - Асуулт 4","prompt":"Усаа юугаар зөөдөг байсан бэ? А.Машинаар Б.Хоёр гараараа В.Мориор Г.Дамнуургаар","options":[],"answers":[],"score":1,"difficulty":"EASY","sourcePage":59,"confidence":0.52,"needsReview":true},{"id":"draft_555","type":"SHORT_ANSWER","title":"ДААЛГАВАРЫН САН - IV АНГИ 1 7 19 2 19 9 - Асуулт 5","prompt":"Өөрийн мэдэх цэцэг, мод, ургамлын нэрийг бичээрэй. Цэцэг-................. ....................................................... Ургамал-.................. .................................................. Мод -........................ ..................................................","options":[],"ans