ers":[],"score":1,"difficulty":"EASY","sourcePage":61,"confidence":0.52,"needsReview":true},{"id":"draft_579","type":"MCQ","title":"ДААЛГАВАРЫН САН - IV АНГИ 1 7 19 2 19 9 - Асуулт 9","prompt":"Холбоо үгийг гүйцээн бичээрэй. Цаг...зүү, Сонгууль .......................дүн Тусламж...................хайрцаг, Багш...........................шохой Үгийн үндэс Залгавар морь, суурь, буурь, амь, завь, тохь -гүй 5.","options":["Өөртөө Дараах үгэнд залгавар залгаж, зөв бичээрэй."],"answers":[],"score":1,"difficulty":"EASY","sourcePage":61,"confidence":0.66,"needsReview":true},{"id":"draft_580","type":"MCQ","title":"ДААЛГАВАРЫН САН - IV АНГИ 1 7 19 2 19 9 - Асуулт 6","prompt":"Өгүүлбэр зохиогоорой. Ой мод - .......................... Ой ухаан -........................ Бөмбөг ой -...................... Зөв харгалзуулаарай. 7.","options":["Өвөө эмээдээ","Дүүдээ","Аав ээждээ"],"answers":[],"score":1,"difficulty":"EASY","sourcePage":61,"confidence":0.66,"needsReview":true},{"id":"draft_581","type":"MCQ","title":"ДААЛГАВАРЫН САН - IV АНГИ 1 7 19 2 19 9 - Асуулт 8","prompt":"Залгаврыг залган бичээд балархай эгшгийн үүргийг тодорхойлоорой. ДААЛГАВАРЫН САН - IV АНГИ Хувилбар 18 ДААЛГАВАРЫН САН - IV АНГИ Хувилбар 19 63 ХАЙРЫН ТҮҮХ Нэгэн цагт Хайр, Уйтгар гуниг, Шунал, Мэдлэг, Аз жаргал, Их зан зэрэг хүний бүх мэдрэмж нэг арал дээр амьдардаг байжээ. Гэтэл арал нь живэх болсон тухай мэдэгдэж, бүгд л арлаа орхин явахын тулд завил бэлтгэцгээжээ. Хайр үргэлж бүгдээс хоцордог байсан тул юу ч болсон эцсийн мөч хүртэл хүлээхээр шийджээ. Тэгээд арал живэх үед Хайр тусламж гуйхаар шийдлээ. Шунал маш том завинд суугаад явахаар зэхэж байхад нь Хайр “Намайг хамт аваад яваач” гэж гуйхад Шунал “Үгүй, завиндаа хэтэрхий их алт, мөнгө ачсан учраас чамайг багтаах зай алга” гэлээ. Хайр үзэсгэлэнтэй сайхан завинд суусан Их зангаас тусламж гуйхад тэр “Би чамд туслахгүй. Чи нэвт норсон байгаа тул завийг минь муухай болгочихно” гэжээ. Хажуудаа байсан Уйтгар гунигаас Хайр “Чамтай хамт явъя\" гэхэд хариуд нь “Өө, Хайр минь, би үнэхээр их гунигтай байгаа тул ганцаар баймаар байна” хэмээв. Аз жаргал хажуугаар нь өнгөрсөн боловч туйлын аз жаргалтай байсан тул Хайр түүнийг дуудавч дуулсангүй. Гэтэл Хайр хэн нэгэн өөрийг нь дуудаж байгааг сонсжээ. “Хайр минь, хүрээд ир би чамайг авч явъя” гэж нэгэн настан дуудсан байлаа. Харин Хайр өөрийгөө азтайд тооцон, баярласандаа түүний нэрийг асуухаа мартжээ. Шинэ газар очсон хойноо тэд өөр өөрийн замаа хөөжээ. Настанд хэчнээн их өртэйгөө мэдэрсэн Хайр Мэдлэгээс “Надад хэн тусалсан юм бэ? гэж асуув. Тэр “Цаг хугацаа” гэж хариулжээ. “Цаг хугацаа гэнэ ээ? Яагаад надад тусалсан юм бол?” Мэдлэг инээмсэглэн байж хариулсан нь “Учир нь зөвхөн Цаг хугацаа л Хайр хэчнээн агуу, чухал зүйл болохыг ойлгодог” гэжээ.","options":["БИЧИХ ЧАДВАРЫН ДААЛГАВАР “Монгол зан заншил” сэдвээр 80-100 үгэнд багтаан эх зохиож бичээрэй."],"answers":[],"score":1,"difficulty":"EASY","sourcePage":61,"confidence":0.66,"needsReview":true},{"id":"draft_582","type":"MCQ","title":"ДААЛГАВАРЫН САН - IV АНГИ 1 7 19 2 19 9 - Асуулт 1","prompt":"Хайр хаана амьдарч байсан бэ?","options":["Ой модонд","Далайд","Арал дээр","Хээр тал дээр"],"answers":[],"score":1,"difficulty":"EASY","sourcePage":63,"confidence":0.66,"needsReview":true},{"id":"draft_583","type":"MCQ","title":"ДААЛГАВАРЫН САН - IV АНГИ 1 7 19 2 19 9 - Асуулт 2","prompt":"Хайр хэн хэнээс тусламж гуйсан бэ? Зөв дараалсан мөрийг олоорой.","options":["Аз жаргал, Уйтгар гуниг, Их зан, Шунал","Их зан, Аз жаргал, Шунал, Уйтгар гуниг","Шунал, Их зан, Уйтгар гуниг, Аз жаргал","Уйтгар гуниг, Шунал, Аз жаргал, Их зан"],"answers":[],"score":1,"difficulty":"EASY","sourcePage":63,"confidence":0.66,"needsReview":true},{"id":"draft_584","type":"MCQ","title":"ДААЛГАВАРЫН САН - IV АНГИ 1 7 19 2 19 9 - Асуулт 3","prompt":"Тэд уснаас юугаар амьд гарсан бэ?","options":["Машинаар","Сэлсээр байгаад","Завиар","Хийтэй бөмбөлөгний хүчээр"],"answers":[],"score":1,"difficulty":"EASY","sourcePage":63,"confidence":0.66,"needsReview":true},{"id":"dr