рав. Буга уужим талаар хар хурдаараа зугтаж баригдалгүй явснаа ойд ормогц эвэр нь модонд тээглэн ороолдож, арсланд баригдчихжээ. Буга амь үрэгдэхийн даваан дээр “ Ямар хачин юм бэ? Би эврээ ямар гоё юм бэ? гэж бахдаж байсан юм сан. Голж байсан нарийхан хөл минь аюулаас аварч, бахдан дэнхгэнүүлж байсан даргар эвэр маань намайг аюулд унагадаг байна шүү. Аливаа юмыг үзэгдэх хэлбэр, өнгөөр нь үнэлж цэгнэж болдоггүй юм байна” гэж бодов.","options":["мод за сургууль сургуулийн хашаа","17-р даалгаврын план зураг дээр зүг чигийг нөхөж бичнэ үү /3 оноо/ С. Масштаб байхгүй ^. 1:20"],"answers":[],"score":1,"difficulty":"EASY","sourcePage":86,"confidence":0.66,"needsReview":true},{"id":"draft_712","type":"MCQ","title":"ДААЛГАВАРЫН САН - IV АНГИ 1 7 19 2 19 9 - Асуулт 1","prompt":"Үлгэрийн үтгад тохирох зүйр үгийг сонгоорой.","options":["Зөв олон талтай","Өөдөө хаясан чулуу БУРУУ ганц талтай Өөрийн толгой дээр"],"answers":[],"score":1,"difficulty":"EASY","sourcePage":87,"confidence":0.66,"needsReview":true},{"id":"draft_713","type":"MCQ","title":"ДААЛГАВАРЫН САН - IV АНГИ 1 7 19 2 19 9 - Асуулт 2","prompt":"Буга гол дээр ус уухаар очихдоо усанд туссан дүрсээ хараад юугаараа бахархсан бэ?","options":["Турьгүй нарийн хөл Б.Даргар эвэр В.Доожоогүй хөл"],"answers":[],"score":1,"difficulty":"EASY","sourcePage":87,"confidence":0.66,"needsReview":true},{"id":"draft_714","type":"MCQ","title":"ДААЛГАВАРЫН САН - IV АНГИ 1 7 19 2 19 9 - Асуулт 3","prompt":"Бугын хийсэн үйл хөдлөл хэд вэ","options":["6","8","7"],"answers":[],"score":1,"difficulty":"EASY","sourcePage":87,"confidence":0.66,"needsReview":true},{"id":"draft_715","type":"MCQ","title":"ДААЛГАВАРЫН САН - IV АНГИ 1 7 19 2 19 9 - Асуулт 4","prompt":"Бугаар ямар хүний зан чанарыг төлөөлөн үзүүлсэн бэ?","options":["Онгироо","Даруу","Сэргэлэн"],"answers":[],"score":1,"difficulty":"EASY","sourcePage":87,"confidence":0.66,"needsReview":true},{"id":"draft_716","type":"MCQ","title":"ДААЛГАВАРЫН САН - IV АНГИ 1 7 19 2 19 9 - Асуулт 5","prom